SELECT IIf(IsNull([FattureRegistrateENDC-PerFatturazioneElettronica-step5.N# Documento])=False,"TROVATA","NON TROVATA") AS CheckIndicom, [FattureRegistrateENDC-PerFatturazioneElettronica-step5].SDI, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[SELL-TO CUSTOMER NO_], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].NAME, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].DocumentNo_, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].DataFattura, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].AmountWithVAT, [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[Document Type], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[Recipient Code], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[File Name XML], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[Date-Time Extraction XML File], [FattureRegistrateENDC-PerFatturazioneElettronica-step3].[User ID Extraction XML File], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Data emissione], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Tipo documento], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Cedente/prestatore], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Cessionario/committente], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[PIVA Cessionario/committente], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Codice ufficio], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].ValoreIndicom, [FattureRegistrateENDC-PerFatturazioneElettronica-step5].Valuta, [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Codice flusso], [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[Data creazione]
FROM [FattureRegistrateENDC-PerFatturazioneElettronica-step3] LEFT JOIN [FattureRegistrateENDC-PerFatturazioneElettronica-step5] ON [FattureRegistrateENDC-PerFatturazioneElettronica-step3].DocumentNo_ = [FattureRegistrateENDC-PerFatturazioneElettronica-step5].[N# documento];

